CREATE TABLE kmmFileInfo (version INTEGER, created DATE, lastModified DATE, baseCurrency CHAR(3), institutions INTEGER, accounts INTEGER, payees INTEGER, tags INTEGER, transactions INTEGER, splits INTEGER, securities INTEGER, prices INTEGER, currencies INTEGER, schedules INTEGER, reports INTEGER, kvps INTEGER, hiInstitutionId INTEGER, hiPayeeId INTEGER, hiTagId INTEGER, hiAccountId INTEGER, hiTransactionId INTEGER, hiScheduleId INTEGER, hiSecurityId INTEGER, hiReportId INTEGER, encryptData CHAR(1), updateInProgress CHAR(1), budgets INTEGER, hiBudgetId INTEGER, hiOnlineJobId INTEGER, hiPayeeIdentifierId INTEGER, logonUser TEXT, logonAt TIMESTAMP, fixLevel INTEGER);
CREATE TABLE kmmCurrencies (ISOcode CHAR(3) NOT NULL PRIMARY KEY, name TEXT NOT NULL, type SMALLINT, typeString TEXT, symbolString VARCHAR(255), smallestCashFraction VARCHAR(24), smallestAccountFraction VARCHAR(24), pricePrecision SMALLINT NOT NULL DEFAULT 4);
CREATE TABLE kmmAccounts (id VARCHAR(32) NOT NULL PRIMARY KEY, institutionId VARCHAR(32), parentId VARCHAR(32), lastReconciled DATE, lastModified DATE, openingDate DATE, accountNumber TEXT, accountType VARCHAR(16) NOT NULL, accountTypeString TEXT, isStockAccount CHAR(1), accountName TEXT, description TEXT, currencyId VARCHAR(32), balance TEXT, balanceFormatted TEXT, transactionCount INTEGER);
CREATE TABLE kmmTransactions (id VARCHAR(32) NOT NULL PRIMARY KEY, txType CHAR(1), postDate DATE, memo TEXT, entryDate DATE, currencyId CHAR(3), bankId TEXT);
CREATE TABLE kmmSplits (transactionId VARCHAR(32) NOT NULL, txType CHAR(1), splitId SMALLINT NOT NULL, payeeId VARCHAR(32), reconcileDate DATE, action VARCHAR(16), reconcileFlag CHAR(1), value TEXT NOT NULL, valueFormatted TEXT, shares TEXT NOT NULL, sharesFormatted TEXT, price TEXT, priceFormatted TEXT, memo TEXT, accountId VARCHAR(32) NOT NULL, costCenterId VARCHAR(32), checkNumber VARCHAR(32), postDate DATE, bankId TEXT, PRIMARY KEY (transactionId, splitId));
CREATE TABLE kmmInstitutions (id VARCHAR(32) NOT NULL PRIMARY KEY, name TEXT NOT NULL);
CREATE TABLE kmmPayees (id VARCHAR(32) NOT NULL PRIMARY KEY, name TEXT);
CREATE TABLE kmmSecurities (id VARCHAR(32) NOT NULL PRIMARY KEY, name TEXT, symbol TEXT, type SMALLINT, typeString TEXT, smallestAccountFraction VARCHAR(24), pricePrecision SMALLINT, tradingCurrency CHAR(3));
CREATE TABLE kmmPrices (fromId VARCHAR(32) NOT NULL, toId VARCHAR(32) NOT NULL, priceDate DATE NOT NULL, price TEXT NOT NULL, priceSource VARCHAR(255), PRIMARY KEY (fromId, toId, priceDate));
CREATE TABLE kmmKeyValuePairs (kvpType VARCHAR(16) NOT NULL, kvpId VARCHAR(32), kvpKey VARCHAR(255) NOT NULL, kvpData TEXT);
